module ALU (
    input [31:0] obf_a,
    input [31:0] b,
    input [1:0] control,
    output reg [31:0] result
);
    always @(*) begin
        case (control)
            2'b00: result = obf_a + b;
            2'b01: result = obf_a - b;
            2'b10: result = obf_a & b;
            2'b11: result = obf_a | b;
            default: result = 32'b0;
        endcase
    end
endmodule
